     2→// FreeLang ThreadPool - 작업 스레드 풀
     3→// ============================================================================
     4→//
     5→// 고정 개수의 워커 스레드로 작업을 처리합니다.
     6→//
     7→// 특징:
     8→// - 고정 크기 스레드 풀
     9→// - 작업 큐 (Channel 기반)
    10→// - Graceful shutdown
    11→// - 작업 완료 대기
    12→//
    13→// 작성일: 2026-03-02
    14→// 단계: Phase B.5 (Week 11-12)
    15→
    16→use std::sync::{Arc, Mutex};
    17→use std::thread;
    18→
    19→// ============================================================================
    20→// Job Type
    21→// ============================================================================
    22→
    23→/// 실행할 작업
    24→pub type Job = Box<dyn FnOnce() + Send + 'static>;
    25→
    26→/// 작업 메시지
    27→enum Message {
    28→    NewJob(Job),
    29→    Terminate,
    30→}
    31→
    32→// ============================================================================
    33→// Worker
    34→// ============================================================================
    35→
    36→/// 워커 스레드
    37→struct Worker {
    38→    id: usize,
    39→    thread: Option<thread::JoinHandle<()>>,
    40→}
    41→
    42→impl Worker {
    43→    /// 새로운 워커를 생성합니다.
    44→    fn new(
    45→        id: usize,
    46→        receiver: Arc<Mutex<std::sync::mpsc::Receiver<Message>>>,
    47→    ) -> Worker {
    48→        let thread = thread::spawn(move || {
    49→            loop {
    50→                let message = receiver.lock().unwrap().recv().unwrap();
    51→
    52→                match message {
    53→                    Message::NewJob(job) => {
    54→                        job();
    55→                    }
    56→                    Message::Terminate => {
    57→                        break;
    58→                    }
    59→                }
    60→            }
    61→        });
    62→
    63→        Worker {
    64→            id,
    65→            thread: Some(thread),
    66→        }
    67→    }
    68→}
    69→
    70→impl Drop for Worker {
    71→    fn drop(&mut self) {
    72→        if let Some(thread) = self.thread.take() {
    73→            thread.join().unwrap();
    74→        }
    75→    }
    76→}
    77→
    78→// ============================================================================
    79→// ThreadPool
    80→// ============================================================================
    81→
    82→pub struct ThreadPool {
    83→    workers: Vec<Worker>,
    84→    sender: std::sync::mpsc::Sender<Message>,
    85→}
    86→
    87→impl ThreadPool {
    88→    /// 새로운 스레드 풀을 생성합니다.
    89→    ///
    90→    /// # Panics
    91→    /// size가 0이면 panic합니다.
    92→    pub fn new(size: usize) -> ThreadPool {
    93→        assert!(size > 0, "ThreadPool size must be > 0");
    94→
    95→        let (sender, receiver) = std::sync::mpsc::channel();
    96→        let receiver = Arc::new(Mutex::new(receiver));
    97→
    98→        let mut workers = Vec::with_capacity(size);
    99→
   100→        for id in 0..size {
   101→            workers.push(Worker::new(id, Arc::clone(&receiver)));
   102→        }
   103→
   104→        ThreadPool { workers, sender }
   105→    }
   106→
   107→    /// 작업을 큐에 추가합니다.
   108→    pub fn execute<F>(&self, f: F)
   109→    where
   110→        F: FnOnce() + Send + 'static,
   111→    {
   112→        let job = Box::new(f);
   113→        self.sender.send(Message::NewJob(job)).unwrap();
   114→    }
   115→
   116→    /// 스레드 풀의 크기를 반환합니다.
   117→    pub fn size(&self) -> usize {
   118→        self.workers.len()
   119→    }
   120→
   121→    /// Graceful shutdown: 모든 작업이 완료될 때까지 대기합니다.
   122→    pub fn shutdown(mut self) {
   123→        for _ in 0..self.workers.len() {
   124→            self.sender.send(Message::Terminate).unwrap();
   125→        }
   126→
   127→        for worker in self.workers.drain(..) {
   128→            if let Some(thread) = worker.thread {
   129→                thread.join().unwrap();
   130→            }
   131→        }
   132→    }
   133→}
   134→
   135→impl Drop for ThreadPool {
   136→    fn drop(&mut self) {
   137→        for _ in 0..self.workers.len() {
   138→            let _ = self.sender.send(Message::Terminate);
   139→        }
   140→
   141→        for worker in self.workers.drain(..) {
   142→            if let Some(thread) = worker.thread {
   143→                let _ = thread.join();
   144→            }
   145→        }
   146→    }
   147→}
